import java.io.*;
import java.util.*;
import java.util.stream.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String raw = br.lines().collect(Collectors.joining("\n"));
        raw = raw.replaceAll("\\\\n", "\n");
        Scanner sc = new Scanner(new StringReader(raw));
        if (!sc.hasNextInt()) {
            return;
        }
        int T = sc.nextInt();
        sc.nextLine(); // consume end of line after T
        StringBuilder out = new StringBuilder();
        for (int t = 0; t < T; t++) {
            if (!sc.hasNextLine()) break;
            String A = sc.nextLine();
            if (!sc.hasNextLine()) break;
            String B = sc.nextLine();
            if (A.length() != B.length()) {
                out.append("NO");
            } else {
                int[] cnt = new int[26];
                for (int i = 0; i < A.length(); i++) {
                    char ca = A.charAt(i);
                    if (ca >= 'a' && ca <= 'z') cnt[ca - 'a']++;
                    else if (ca >= 'A' && ca <= 'Z') cnt[ca - 'A']++;
                }
                for (int i = 0; i < B.length(); i++) {
                    char cb = B.charAt(i);
                    if (cb >= 'a' && cb <= 'z') cnt[cb - 'a']--;
                    else if (cb >= 'A' && cb <= 'Z') cnt[cb - 'A']--;
                }
                boolean ok = true;
                for (int v : cnt) {
                    if (v != 0) { ok = false; break; }
                }
                out.append(ok ? "YES" : "NO");
            }
            if (t != T - 1) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

